mapper.select:
SELECT a.apply_id, a.event_id, COALESCE(a.event_title, e.title) AS event_title, e.event_date, a.member_id, a.member_name, a.apply_date, a.status FROM erp_event_apply a LEFT JOIN erp_event e ON a.event_id = e.event_id
AND (a.member_name LIKE '%' || #{keyword} || '%' OR e.title LIKE '%' || #{keyword} || '%')
ORDER BY a.apply_date DESC LIMIT #{limit} OFFSET #{offset}
